function updateInputField(){if("shorten"!==window.dataPage)return;const t=document.querySelector("form #inlink"),e=document.querySelector("form .btn-newtab");t.value=getUrlVars(window.location.href).b,e.href=getUrlVars(window.location.href).b,e.setAttribute("target","_about"),t.setAttribute("readonly","")}updateInputField();